types/blog.ts 생성:

export interface BlogPost {
  id: string
  title: string
  category: string
  tags: string[]
  publishedAt: string
  status: '초안' | '발행됨'
  slug: string
}

export interface NotionRichText {
  plainText: string
  href: string | null
  annotations: { bold: boolean; italic: boolean; strikethrough: boolean; underline: boolean; code: boolean }
}

export interface NotionCodeBlock {
  language: string
  richText: NotionRichText[]
}

export interface NotionImageBlock {
  type: 'external' | 'file'
  url: string
  caption: NotionRichText[]
}

export type NotionBlockType = 'paragraph' | 'heading_1' | 'heading_2' | 'heading_3' | 'bulleted_list_item' | 'numbered_list_item' | 'code' | 'image' | 'quote' | 'divider'

export interface NotionBlock {
  id: string
  type: NotionBlockType
  content: NotionRichText[] | NotionCodeBlock | NotionImageBlock | null
  children?: NotionBlock[]
}

export interface FetchPostsOptions {
  pageSize?: number
  startCursor?: string
  category?: string
}

export interface FetchPostsResult {
  posts: BlogPost[]
  hasMore: boolean
  nextCursor?: string
}

