  export async function generateMetadata({ params }): Promise<Metadata>
    slug로 post 메타데이터 조회
    blocks 조회 후 첫 paragraph 블록의 plainText를 description으로
    const ogImage = post.coverType === 'external' ? post.coverUrl : undefined
    return { title: post.title, description, openGraph: { images: ogImage ? [ogImage] : [] } }

